const SYSTEM_PROMPT = `You are an AI Product Manager helping run a structured software discovery session.

You guide the user through these stages in order:
1. DISCOVERY: understand the problem, context, users affected
2. HYPOTHESES: formulate 3 testable hypotheses
3. METRICS: define 3 measurable success KPIs
4. SPEC READY: when user says 'gerar spec' or 'generate spec', produce the full PRD

When producing the PRD (stage 4), use this exact format:

---SPEC-START---
## Feature Name
[verb-noun, e.g. "Manage Personal Tasks"]

## Background
[1 paragraph]

## Functional Requirements
RF-01: The system MUST ...
RF-02: The system MUST ...
[5-8 requirements]

## Non-Functional Requirements
[3-5: performance, security, observability]

## Acceptance Criteria
[Given/When/Then for each RF]

## Out of Scope
[3+ items]

## Definition of Done
[checklist]
---SPEC-END---

For all other messages, respond conversationally to refine the discovery. Keep responses concise.`;

const messages = $input.first().json.messages || [];
const userMessage = $input.first().json.chatInput || '';

// Build message history for multi-turn
const history = messages.map(m => ({ role: m.role, content: m.content }));
history.push({ role: 'user', content: userMessage });

const allMessages = [{ role: 'system', content: SYSTEM_PROMPT }, ...history];

const resp = await fetch('http://ollama:11434/api/chat', {
  method: 'POST',
  headers: { 'Content-Type': 'application/json' },
  body: JSON.stringify({
    model: 'qwen3-coder:30b',
    stream: false,
    options: { temperature: 0.3 },
    messages: allMessages
  })
});

if (!resp.ok) throw new Error(`Ollama error: ${resp.status} ${await resp.text()}`);
const data = await resp.json();
const reply = data.message.content;

// If response contains a spec, save it to the handoff file
if (reply.includes('---SPEC-START---')) {
  const specMatch = reply.match(/---SPEC-START---([\s\S]*?)---SPEC-END---/);
  if (specMatch) {
    const spec = specMatch[1].trim();
    // Write spec to handoff file via n8n filesystem
    const fs = require('fs');
    fs.mkdirSync('/tmp/sdlc-poc', { recursive: true });
    fs.writeFileSync('/tmp/sdlc-poc/spec.md', spec, 'utf8');
  }
}

return [{ json: { output: reply } }];
